// Pre-composited white plate + brand logo, centered on the 1024px
// export QR (see /api/qr/[id]/route.js). Stored as RAW RGBA bytes (not a
// PNG) — pngjs's PNG.sync.read() calls Node's zlib.Inflate the old
// "callable without new" way, which throws under the Workers
// nodejs_compat polyfill (a real ES6 class). Encoding (PNG.sync.write,
// zlib.deflateSync) has no such issue, so we only ever encode, never
// decode, at request time.
export const QR_LOGO_BADGE_SIZE = 200;
export const QR_LOGO_BADGE_RGBA_BASE64 =
  "";
